selector_to_html = {"a[href=\"system.html#battery-information\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Informations sur la batterie<a class=\"headerlink\" href=\"#battery-information\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"system.html#restore-default-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Restaurer les param\u00e8tres par d\u00e9faut<a class=\"headerlink\" href=\"#restore-default-settings\" title=\"Lien vers cette rubrique\">#</a></h2><p>Lorsqu\u2019une erreur inconnue se produit sur le scanner, vous pouvez r\u00e9initialiser le scanner en restaurant les param\u00e8tres par d\u00e9faut.</p>", "a[href=\"system.html#volume-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">R\u00e9glages du volume<a class=\"headerlink\" href=\"#volume-settings\" title=\"Lien vers cette rubrique\">#</a></h2><p>Scannez le code de r\u00e9glage correspondant pour activer/d\u00e9sactiver l\u2019invite sonore du scanner</p>", "a[href=\"#wifi-wireless-scanner-quick-setup-guide\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Guide d\u2019installation rapide du scanner sans fil <strong>WiFi</strong><a class=\"headerlink\" href=\"#wifi-wireless-scanner-quick-setup-guide\" title=\"Lien vers cette rubrique\">#</a></h1>", "a[href=\"bluetooth.html#ios-popup-hide-keyboard\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Popup/Cacher Clavier IOS<a class=\"headerlink\" href=\"#ios-popup-hide-keyboard\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"wireless.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Mode de transmission Wi-Fi<a class=\"headerlink\" href=\"#wi-fi-transmission-mode\" title=\"Lien vers cette rubrique\">#</a></h1><h2>Modifier l\u2019ID de l\u2019appareil<a class=\"headerlink\" href=\"#modify-device-id\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"bluetooth.html#bluetooth-hid\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">HID Bluetooth<a class=\"headerlink\" href=\"#bluetooth-hid\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"bluetooth.html#modify-bluetooth-name\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modifier le nom du Bluetooth<a class=\"headerlink\" href=\"#modify-bluetooth-name\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"system.html#get-firmware-version\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Obtenir la version du Firmware<a class=\"headerlink\" href=\"#get-firmware-version\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"keyboard.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Param\u00e8tres du clavier<a class=\"headerlink\" href=\"#keyboard-settings\" title=\"Lien vers cette rubrique\">#</a></h1><h2>R\u00e9glages du cas<a class=\"headerlink\" href=\"#case-settings\" title=\"Lien vers cette rubrique\">#</a></h2><h3>Normale<a class=\"headerlink\" href=\"#normal\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"keyboard.html#case-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">R\u00e9glages du cas<a class=\"headerlink\" href=\"#case-settings\" title=\"Lien vers cette rubrique\">#</a></h2><h3>Normale<a class=\"headerlink\" href=\"#normal\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"wireless.html#data-upload-format\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Format de t\u00e9l\u00e9chargement des donn\u00e9es<a class=\"headerlink\" href=\"#data-upload-format\" title=\"Lien vers cette rubrique\">#</a></h2><h3>Contenu original du code-barres<a class=\"footnote-reference brackets\" href=\"#id2\" id=\"id1\" role=\"doc-noteref\"><span class=\"fn-bracket\">[</span>1<span class=\"fn-bracket\">]</span></a><a class=\"headerlink\" href=\"#original-barcode-content1\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"working.html#normal-mode\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Mode Normal<a class=\"headerlink\" href=\"#normal-mode\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"wireless.html#network-configuration\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Configuration du r\u00e9seau<a class=\"headerlink\" href=\"#network-configuration\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"bluetooth.html#bluetooth-ble\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Bluetooth BLE<a class=\"headerlink\" href=\"#bluetooth-ble\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"system.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Param\u00e8tres du syst\u00e8me<a class=\"headerlink\" href=\"#system-settings\" title=\"Lien vers cette rubrique\">#</a></h1><h2>Restaurer les param\u00e8tres par d\u00e9faut<a class=\"headerlink\" href=\"#restore-default-settings\" title=\"Lien vers cette rubrique\">#</a></h2><p>Lorsqu\u2019une erreur inconnue se produit sur le scanner, vous pouvez r\u00e9initialiser le scanner en restaurant les param\u00e8tres par d\u00e9faut.</p>", "a[href=\"system.html#sleep-time\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Temps de sommeil<a class=\"headerlink\" href=\"#sleep-time\" title=\"Lien vers cette rubrique\">#</a></h2><p>En scannant le code de r\u00e9glage suivant, vous pouvez r\u00e9gler le scanner pour qu\u2019il passe en mode veille apr\u00e8s une certaine p\u00e9riode de temps o\u00f9 aucun code n\u2019est scann\u00e9, afin de r\u00e9duire la consommation d\u2019\u00e9nergie.</p>", "a[href=\"bluetooth.html#bluetooth-keyboard-transmission-speed\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Vitesse de transmission du clavier Bluetooth<a class=\"headerlink\" href=\"#bluetooth-keyboard-transmission-speed\" title=\"Lien vers cette rubrique\">#</a></h2><h3>Haute Vitesse<a class=\"headerlink\" href=\"#high-speed\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"bluetooth.html#bluetooth-spp\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">SPP Bluetooth<a class=\"headerlink\" href=\"#bluetooth-spp\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"keyboard.html#keyboard-language\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Langue du clavier<a class=\"headerlink\" href=\"#keyboard-language\" title=\"Lien vers cette rubrique\">#</a></h2><h3>Obtenir la langue actuelle du clavier<a class=\"headerlink\" href=\"#get-current-keyboard-language\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"bluetooth.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Mode Bluetooth<a class=\"headerlink\" href=\"#bluetooth-mode\" title=\"Lien vers cette rubrique\">#</a></h1><h2>HID Bluetooth<a class=\"headerlink\" href=\"#bluetooth-hid\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"wireless.html#data-transmission-protocol\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Protocole de transmission de donn\u00e9es<a class=\"headerlink\" href=\"#data-transmission-protocol\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"wireless.html#data-rceiving-format\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Format de Rceiving des donn\u00e9es<a class=\"headerlink\" href=\"#data-rceiving-format\" title=\"Lien vers cette rubrique\">#</a></h2><h3>Code vocal<a class=\"headerlink\" href=\"#voice-code\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"working.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Mode de travail<a class=\"headerlink\" href=\"#working-mode\" title=\"Lien vers cette rubrique\">#</a></h1><p>Dans la zone de travail en dehors de la port\u00e9e de la 2. R\u00e9cepteur G ou signal Bluetooth, vous pouvez activer le mode de stockage du scanner en suivant les \u00e9tapes d\u00e9crites ci-dessous. Dans ce mode, toutes les donn\u00e9es num\u00e9ris\u00e9es seront stock\u00e9es directement dans le scanner. Avant de t\u00e9l\u00e9charger les donn\u00e9es, il sera sauvegard\u00e9 en permanence dans le scanner afin que vous puissiez t\u00e9l\u00e9charger les donn\u00e9es lorsque le scanner est dans la plage de signal de r\u00e9ception.</p>", "a[href=\"bluetooth.html#clear-pairing-information\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Effacer les informations d\u2019appairage<a class=\"headerlink\" href=\"#clear-pairing-information\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"wireless.html#modify-device-id\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modifier l\u2019ID de l\u2019appareil<a class=\"headerlink\" href=\"#modify-device-id\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"working.html#storage-mode\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Mode de stockage<a class=\"headerlink\" href=\"#storage-mode\" title=\"Lien vers cette rubrique\">#</a></h2><h3>Envoi de donn\u00e9es<a class=\"footnote-reference brackets\" href=\"#id2\" id=\"id1\" role=\"doc-noteref\"><span class=\"fn-bracket\">[</span>1<span class=\"fn-bracket\">]</span></a><a class=\"headerlink\" href=\"#data-upload1\" title=\"Lien vers cette rubrique\">#</a></h3>"}
skip_classes = ["headerlink", "sd-stretched-link", "sd-rounded-pill"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
